function candidate(separator, parts) {
  const folderText = parts.dir || parts.root;
  const fileText = parts.base || `${parts.name || ""}${parts.ext || ""}`;

  if (!folderText) {
    return fileText;
  }

  return folderText === parts.root
    ? folderText + fileText
    : folderText + separator + fileText;
}
